function ring(key,fx){ const svg=SVG[key]; if(!svg) return ""; return '<span class="fxring '+(fx||"")+'">'+svg+'</span>'; }
function badge(key){ const svg=SVG[key]; if(!svg) return ""; return '<span class="fxbadge">'+svg+'</span>'; }
function icon(key,cls){ const svg=SVG[key]; if(!svg) return ""; return '<span class="'+(cls||"fxicon")+'">'+svg+'</span>'; }
function has(key){ return !!SVG[key]; }
return { SVG, ring, badge, icon, has };
